6556,0.02908416,-0.02424708,0.02527352,0.03728513,-0.06031698,0.13241328,0.05419267,0.01884441,-0.03832111,0.01674329,-0.00941579,0.01841765,0.01677935,-0.01219303,0.01323817,-0.00818312,-0.00234812,-0.00334246,0.02676265,-0.00768243,-0.00640906,0.10889474,-0.05689081,-0.05151476,-0.05719736,-0.00761656,-0.01462414,-0.06699296,0.00981361,0.00095985,-0.05414541,-0.00675890,0.00304849,0.02018544,-0.01567817,-0.05560144,0.01254508,0.01332514,-0.05194578,0.06555305,0.05711899,0.03152750]',E'Stored procedure returning cursor (result set)\n\n```go\nvar rset1, rset2 driver.Rows\n\nconst query = `BEGIN Package.StoredProcA(123, :1, :2); END;`\n\nstmt, err := db.PrepareContext(ctx, query)\nif err != nil {\n    return fmt.Errorf("%s: %w", query, err)\n}\ndefer stmt.Close()\nif _, err := stmt.ExecContext(ctx, sql.Out{Dest: &rset1}, sql.Out{Dest: &rset2}); err != nil {\n	log.Printf("Error running %q: %+v", query, err)\n	return\n}\ndefer rset1.Close()\ndefer rset2.Close()\n\ncols1 := rset1.(driver.RowsColumnTypeScanType).Columns()\ndests1 := make([]driver.Value, len(cols1))\nfor {\n	if err := rset1.Next(dests1); err != nil {\n		if err == io.EOF {\n			break\n		}\n		rset1.Close()\n		return err\n	}\n	fmt.Println(dests1)\n}\n\ncols2 := rset1.(driver.RowsColumnTypeScanType).Columns()\ndests2 := make([]driver.Value, len(cols2))\nfor {\n	if err := rset2.Next(dests2); err != nil {\n		if err == io.EOF {\n			break\n		}\n		rset2.Close()\n		return err\n	}\n	fmt.Println(dests2)\n}\n```','{"source": "oracle", "version": "23", "language": "go", "title": "Go DRiver for ORacle", "section_title": "README", "url": "https://github.com/godror/godror/blob/main/README.md", "topics": "oracle,go,sql,README", "categories": "database,sql,oracle"}');
